class Solution:
    def findRestaurant(self, list1, list2):
        pos = {name: i for i, name in enumerate(list1)}
        best = None
        res = []
        for j, name in enumerate(list2):
            if name in pos:
                s = pos[name] + j
                if best is None or s < best:
                    best = s
                    res = [name]
                elif s == best:
                    res.append(name)
        return res

