var findRestaurant = function(list1, list2) {
    const pos = new Map();
    list1.forEach((name, i) => pos.set(name, i));
    let best = Infinity;
    let res = [];
    list2.forEach((name, j) => {
        if (pos.has(name)) {
            const s = pos.get(name) + j;
            if (s < best) {
                best = s;
                res = [name];
            } else if (s === best) {
                res.push(name);
            }
        }
    });
    return res;
};
